var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"하아…… 하…….","JPN":"はあ……はあ……","ENG":"*Huff*... *Huff*...","TWN":"哈啊……哈……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"말도 안 돼. 아까부터 한 번도 공격이 닿지 않아.","JPN":"嘘でしょ。さっきから攻撃が全然当たらない。","ENG":"Impossible. None of my attacks are working.","TWN":"怎麼會這樣。從剛才開始，就好像沒有擊中過一次。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"이쪽도 마찬가지야. 그냥 아무렇게나 휘두르는 것 같은데 쏘는 족족 튕겨 나가고 있어.","JPN":"こちらも同じよ。ただ振り回しているだけに見えるのに、撃ったらことごとく跳ね返される。","ENG":"Same here. It looks like he’s just swinging his sword around, but all the bullets are being deflected.","TWN":"胡亂揮幾下，就彈走了我所有的子彈嗎。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"꼭 어른한테 휘둘리는 어린애가 된 기분이네.","JPN":"まるで大人に遊ばれている子どもになったような気分だね。","ENG":"I feel like a kid being played by an adult.","TWN":"就像是在陪小孩玩家家酒……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배, 저것도 무슨 검술이야?","JPN":"先輩、あれも剣術の一種か何かなの？","ENG":"Is that some type of swordsmanship, Shiyoon?","TWN":"前輩，那也是一種什麼劍法嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 제 눈에도 아무렇게나 휘두르는 모양새로 보이네요.","JPN":"ハハ、僕にもただ振り回しているだけに見えます。","ENG":"Ha ha. It looks like reckless swinging to me as well.","TWN":"哈哈，在我看來也是毫無章法的樣子。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"아마 본래 실력을 내지 않기 때문이겠죠.","JPN":"おそらく本来の実力を出していないからでしょうね。","ENG":"It's probably because he wants to hide his true powers.","TWN":"大概是因為他還沒有發揮本來的實力吧。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"본래 실력이 아니라고……? 저게?","JPN":"本来の実力じゃない……？　あれが？","ENG":"That's not all he's got...? Really?","TWN":"沒發揮本來的實力……？還？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"이제 흥분이 좀 가라앉으셨나요?","JPN":"やっと落ち着いてくれましたか？","ENG":"Has everyone calmed down now?","TWN":"現在冷靜點了嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"몰래 따라왔던 건 죄송합니다. 여러분이 마왕의 하수인이 아니라고 확신할 수 없었거든요.","JPN":"こっそり後をつけてきたことは謝ります。皆さんが魔王の手下ではないとの確信が持てなくて。","ENG":"I apologize for following you. I wasn't sure whether you were the henchmen of the Demon Lord or not.","TWN":"很抱歉偷偷跟著你們。因為我不能確定你們不是魔王的手下。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"하지만 이제 알겠습니다. 여러분에게서는 그들과 같은 기운이 느껴지지 않아요.","JPN":"でももうよくわかりました。皆さんからは奴らのような気を感じません。","ENG":"But now I know. I don't feel the same aura from you.","TWN":"不過現在我知道了。你們身上沒有和他們一樣的氣息。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"마왕의 하수인이라니?","JPN":"魔王の手下？","ENG":"The Demon Lord's henchmen?","TWN":"魔王的手下？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그게 무슨 소리야? 마왕은 선배잖아!","JPN":"どういうこと？　魔王は、先輩でしょう！","ENG":"What are you talking about? You’re the Demon Lord!","TWN":"你在說什麼啊？魔王明明是前輩你啊！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"네……? 누가 마왕이라고요? 제가요?","JPN":"え……？　誰が魔王だって？　僕が？","ENG":"Huh...? Who is? Me?","TWN":"什麼……？你說誰是魔王？我嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"침착하세요, 미나 양.","JPN":"落ち着きましょう、ミナさん。","ENG":"Relax, Mina.","TWN":"冷靜點，米娜。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"검을 맞대면서 느꼈지만, 저 분은 저희와 싸우고 싶은 마음이 없는 것 같네요.","JPN":"剣を交えてわかったのですが、僕たちへの敵意はないようです。","ENG":"I could feel it when we just fought, but it doesn’t seem like he’s interested in going against us.","TWN":"剛才打鬥的時候，那個人的劍上好像並沒有殺意。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"군대까지 동원해 놓고 말이야?","JPN":"軍隊まで引き連れてきていたのに？","ENG":"What about all the troops?","TWN":"那之前的那些軍隊？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"네. 우리가 쓰러뜨려야 할 분이라기엔, 미나 양을 보고도 아무 반응이 없어요.","JPN":"はい、僕たちの敵というには、ミナさんを見て何も反応しないなんておかしいです。","ENG":"Well, if he wanted to, he would have done something when he saw Mina.","TWN":"嗯，真要這麼說的話，他在看到米娜你後也沒有任何反應。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"그럼……. 이것도 선배가 잡혀 있던 도시처럼 일종의 환각일까?","JPN":"じゃあ……これも先輩が閉じ込められていた街みたいに、幻覚のようなものってこと？","ENG":"Then... Do you think this is also some sort of a hallucination, like the city you were trapped in?","TWN":"那……這裡也和以前困住前輩的城市一樣，是幻覺嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"오히려 이쪽이 원본이지 않을까요?","JPN":"むしろこちらの方が本当の姿なのではないでしょうか？","ENG":"No, I think this is real.","TWN":"我倒是覺得這裡是真實發生過的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"지금이 괴로울수록 좋았던 시절에 매달리고.","JPN":"今が辛いと、過去に囚われるようになり。","ENG":"The more pain you are in currently, the more you drift off into the good old days...","TWN":"如今越痛苦，就越執著於曾經的美好時光。"},"stage":{"bg":"CASTLE_01","bgm":null,"filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"후회할수록 과거의 실수를 곱씹게 되니 말이죠.","JPN":"後悔すればするほど過去の過ちは強く想起されますからね。","ENG":"And the more you regret the past, the more you become obsessed with your mistakes.","TWN":"越後悔，就越會回首過往的錯誤。"},"stage":{"bg":"CASTLE_01","bgm":null,"filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그럼 이게, 레이 선배의 과거라고……?","JPN":"じゃあ、これがレイ先輩の過去だっていうの……？","ENG":"Are you saying... that this is Ray's past?","TWN":"那麼，這是雷伊前輩的過去……？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"……경계하시는 마음은 이해합니다.","JPN":"……警戒する気持ちはわかります。","ENG":"...I understand your hostility.","TWN":"……我能理解你們的戒備之心。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"하지만 여긴 이미 마왕의 세력권 아래 놓인 곳이에요.","JPN":"ですが、ここはすでに魔王の支配下に置かれた場所です。","ENG":"But this region is already under the Demon Lord's influence.","TWN":"不過這個地方已經處於魔王的勢力範圍內了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"오래 머물다가 마왕의 군세에게 발각되기라도 하면 위험해질 겁니다.","JPN":"あまり長居すると、魔王の軍勢にバレて危ない目に遭ってしまいますよ。","ENG":"If we stay here, it won't be long before his forces detect us.","TWN":"待久了，萬一被魔王的軍隊發現會很危險。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"저와 함께 가요. 안전한 곳까지 안내해 드릴게요.","JPN":"僕と行きましょう。安全な所まで案内します。","ENG":"Come with me. I'll guide you towards somewhere safe.","TWN":"和我一起走吧。我帶你們去安全的地方。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};